Query.Sql:
with ug as ( select distinct -- NHS Number: Patient identifier, used to link to the person table. Record ->> '$.LinkagePatientId.NhsNumber.@extension' as NhsNumber,
-- Primary Procedure (OPCS): The primary OPCS-4 procedure code, maps to procedure_source_value in procedure_occurrence. -- Will be mapped to a standard OMOP concept in a later ETL step via OPCS-4 vocabulary lookup. unnest ([[Record ->> '$.Treatment.Surgery.PrimaryProcedureOpcs.@code'], Record ->> '$.Treatment[*].Surgery.PrimaryProcedureOpcs.@code'], recursive := true) as PrimaryProcedureOpcs,
-- Procedure Date: The date the procedure was performed, maps to procedure_date in procedure_occurrence. -- Currently in string format (CCYY-MM-DD), will be cast to date type in a later ETL step. unnest ([[Record ->> '$.Treatment.Surgery.ProcedureDate'], Record ->> '$.Treatment[*].Surgery.ProcedureDate'], recursive := true) as ProcedureDate from omop_staging.cosd_staging_901 where type = 'UG' ) select distinct NhsNumber, PrimaryProcedureOpcs, ProcedureDate from ug where NhsNumber is not null and PrimaryProcedureOpcs is not null;
